import{_ as i,o as s,c as e,a2 as t}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Node.js 与 Git 环境","description":"","frontmatter":{},"headers":[],"relativePath":"guide/nodejs-git.md","filePath":"guide/nodejs-git.md","lastUpdated":1781767129000}'),l={name:"guide/nodejs-git.md"};function n(h,a,p,o,d,r){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="node-js-与-git-环境" tabindex="-1">Node.js 与 Git 环境 <a class="header-anchor" href="#node-js-与-git-环境" aria-label="Permalink to &quot;Node.js 与 Git 环境&quot;">​</a></h1><p>如果你需要在本地使用 Codex、CC Switch 或其他命令行工具，建议先准备 Node.js 和 Git。Node.js 用来运行 npm 生态里的命令行工具，Git 用来下载项目、管理代码和配合后续部署。</p><h2 id="安装前先确认" tabindex="-1">安装前先确认 <a class="header-anchor" href="#安装前先确认" aria-label="Permalink to &quot;安装前先确认&quot;">​</a></h2><p>建议安装：</p><ul><li>Node.js：选择 LTS 版本。</li><li>npm：安装 Node.js 时会自动附带。</li><li>Git：选择当前系统对应的稳定版本。</li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>LTS 是长期维护版本，更适合日常使用。不要为了追新安装实验版本，除非你明确知道自己需要它。</p></div><h2 id="macos-安装" tabindex="-1">macOS 安装 <a class="header-anchor" href="#macos-安装" aria-label="Permalink to &quot;macOS 安装&quot;">​</a></h2><h3 id="方式一-使用-homebrew" tabindex="-1">方式一：使用 Homebrew <a class="header-anchor" href="#方式一-使用-homebrew" aria-label="Permalink to &quot;方式一：使用 Homebrew&quot;">​</a></h3><p>如果你的电脑已经安装 Homebrew，可以直接在终端执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">brew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span></span></code></pre></div><p>安装完成后，关闭当前终端窗口，再重新打开一个终端。</p><h3 id="方式二-使用官方安装包" tabindex="-1">方式二：使用官方安装包 <a class="header-anchor" href="#方式二-使用官方安装包" aria-label="Permalink to &quot;方式二：使用官方安装包&quot;">​</a></h3><p>如果你不熟悉命令行，可以使用官方安装包：</p><ul><li>Node.js：<a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a></li><li>Git：<a href="https://git-scm.com/downloads" target="_blank" rel="noreferrer">git-scm.com/downloads</a></li></ul><p>下载后按安装器提示一路安装即可。安装完成后，同样需要重新打开终端。</p><h2 id="windows-安装" tabindex="-1">Windows 安装 <a class="header-anchor" href="#windows-安装" aria-label="Permalink to &quot;Windows 安装&quot;">​</a></h2><h3 id="方式一-使用官方安装包" tabindex="-1">方式一：使用官方安装包 <a class="header-anchor" href="#方式一-使用官方安装包" aria-label="Permalink to &quot;方式一：使用官方安装包&quot;">​</a></h3><ol><li>打开 <a href="https://nodejs.org/" target="_blank" rel="noreferrer">nodejs.org</a>，下载 LTS 版本安装包。</li><li>打开 <a href="https://git-scm.com/downloads" target="_blank" rel="noreferrer">git-scm.com/downloads</a>，下载 Windows 版本安装包。</li><li>双击安装包，按默认选项安装。</li><li>安装完成后，重新打开 PowerShell、命令提示符或 Windows Terminal。</li></ol><h3 id="方式二-使用-winget" tabindex="-1">方式二：使用 winget <a class="header-anchor" href="#方式二-使用-winget" aria-label="Permalink to &quot;方式二：使用 winget&quot;">​</a></h3><p>如果你的系统支持 winget，可以在 PowerShell 中执行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">id OpenJS.NodeJS.LTS </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">winget install </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">id Git.Git </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span></span></code></pre></div><p>安装完成后，关闭当前终端窗口，再重新打开一个终端。</p><h2 id="验证安装结果" tabindex="-1">验证安装结果 <a class="header-anchor" href="#验证安装结果" aria-label="Permalink to &quot;验证安装结果&quot;">​</a></h2><p>重新打开终端后，依次执行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span></span></code></pre></div><p>如果三条命令都能看到版本号，说明 Node.js、npm 和 Git 已经安装成功。</p><p>还可以检查命令路径：</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-pJz9r" id="tab-LwK-6mz" checked><label data-title="macOS" for="tab-LwK-6mz">macOS</label><input type="radio" name="group-pJz9r" id="tab-0ghve_V"><label data-title="Windows" for="tab-0ghve_V">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> node</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> npm</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">which</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> node</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> npm</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">where</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> git</span></span></code></pre></div></div></div><p>这些命令会显示工具安装在电脑上的具体位置。只要能显示路径，通常就说明系统已经能找到它们。</p><h2 id="配置-git-用户信息" tabindex="-1">配置 Git 用户信息 <a class="header-anchor" href="#配置-git-用户信息" aria-label="Permalink to &quot;配置 Git 用户信息&quot;">​</a></h2><p>第一次使用 Git 时，建议先设置提交时显示的姓名和邮箱：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;你的名字&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> user.email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;你的邮箱&quot;</span></span></code></pre></div><p>设置后可以用下面命令确认：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> config</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --global</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --list</span></span></code></pre></div><p>如果能看到 <code>user.name</code> 和 <code>user.email</code>，说明 Git 基础配置已经完成。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="node、npm-或-git-命令找不到" tabindex="-1">node、npm 或 git 命令找不到 <a class="header-anchor" href="#node、npm-或-git-命令找不到" aria-label="Permalink to &quot;node、npm 或 git 命令找不到&quot;">​</a></h3><p>通常是安装后终端没有重新加载环境变量。先关闭所有终端窗口，再重新打开终端执行验证命令。</p><p>如果还是找不到：</p><ul><li>确认安装包已经完整安装成功。</li><li>Windows 用户确认安装 Git 时没有取消添加 PATH 的选项。</li><li>macOS 用户如果使用 Homebrew，确认 <code>brew doctor</code> 没有明显错误提示。</li></ul><h3 id="npm-下载速度慢" tabindex="-1">npm 下载速度慢 <a class="header-anchor" href="#npm-下载速度慢" aria-label="Permalink to &quot;npm 下载速度慢&quot;">​</a></h3><p>如果 npm 安装工具时速度很慢，可以先换网络环境再试。不要随意复制陌生来源的一键换源命令，避免后续下载到不可控的软件包。</p><h3 id="已经装过-node-js-还需要重装吗" tabindex="-1">已经装过 Node.js，还需要重装吗 <a class="header-anchor" href="#已经装过-node-js-还需要重装吗" aria-label="Permalink to &quot;已经装过 Node.js，还需要重装吗&quot;">​</a></h3><p>不一定。只要 <code>node -v</code> 和 <code>npm -v</code> 都能正常显示版本号，并且后续工具可以正常安装，就可以继续使用当前版本。遇到兼容问题时，再考虑升级到 LTS 版本。</p><h3 id="需要安装-nvm、fnm-或-volta-吗" tabindex="-1">需要安装 nvm、fnm 或 Volta 吗 <a class="header-anchor" href="#需要安装-nvm、fnm-或-volta-吗" aria-label="Permalink to &quot;需要安装 nvm、fnm 或 Volta 吗&quot;">​</a></h3><p>普通用户不需要一开始就安装版本管理工具。只有当你需要同时维护多个 Node.js 版本，或者不同项目要求不同 Node.js 版本时，再考虑使用 nvm、fnm 或 Volta。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成 Node.js 和 Git 环境后，可以继续配置：</p><ul><li><a href="/guide/api-key">请求地址 / API Key</a></li><li><a href="/guide/config-switch">CC Switch 使用教程</a></li></ul><div class="tip custom-block"><p class="custom-block-title">提示</p><p>后续如果安装 Codex 或其他命令行工具失败，先回到本页重新执行验证命令，确认 Node.js、npm 和 Git 都能正常使用。</p></div>`,50)])])}const g=i(l,[["render",n]]);export{c as __pageData,g as default};
